// src/utils/crypto.js
export function generateRandomString(length = 64) {
  const array = new Uint8Array(length);
  window.crypto.getRandomValues(array);
  return Array.from(array, (byte) => byte.toString(16).padStart(2, '0')).join('');
}

export async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const digest = await window.crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

export function generateNonce() {
  return generateRandomString(32);
}

// src/utils/tokenUtils.js
export function decodeJwtPayload(token) {
  if (!token || typeof token !== 'string') {
    throw new Error('Invalid token');
  }

  const parts = token.split('.');
  if (parts.length !== 3) {
    throw new Error('Invalid JWT format');
  }

  const base64Url = parts[1];
  const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
  const paddedBase64 = base64.padEnd(base64.length + (4 - (base64.length % 4)) % 4, '=');

  try {
    const jsonPayload = decodeURIComponent(
      atob(paddedBase64)
        .split('')
        .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join('')
    );
    return JSON.parse(jsonPayload);
  } catch (e) {
    throw new Error('Failed to decode JWT payload');
  }
}

export function validateIdToken(idToken, clientId, nonce, issuer) {
  const payload = decodeJwtPayload(idToken);

  // Validate issuer
  if (issuer && payload.iss !== issuer) {
    throw new Error(`Invalid issuer. Expected ${issuer}, got ${payload.iss}`);
  }

  // Validate audience
  const audiences = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
  if (!audiences.includes(clientId)) {
    throw new Error('Invalid audience');
  }

  // Validate nonce
  if (nonce && payload.nonce !== nonce) {
    throw new Error('Invalid nonce');
  }

  // Validate expiration
  const now = Math.floor(Date.now() / 1000);
  if (payload.exp && payload.exp < now) {
    throw new Error('Token has expired');
  }

  // Validate issued at (with 5 minute clock skew tolerance)
  if (payload.iat && payload.iat > now + 300) {
    throw new Error('Token issued in the future');
  }

  return payload;
}

export function isTokenExpired(token) {
  try {
    const payload = decodeJwtPayload(token);
    const now = Math.floor(Date.now() / 1000);
    return payload.exp < now;
  } catch {
    return true;
  }
}

// src/utils/oidcDiscovery.js
const discoveryCache = new Map();

export async function fetchDiscoveryDocument(authority) {
  if (discoveryCache.has(authority)) {
    return discoveryCache.get(authority);
  }

  const wellKnownUrl = `${authority.replace(/\/$/, '')}/.well-known/openid-configuration`;

  const response = await fetch(wellKnownUrl);
  if (!response.ok) {
    throw new Error(`Failed to fetch OIDC discovery document: ${response.status}`);
  }

  const doc = await response.json();

  // Validate required fields
  const requiredFields = ['authorization_endpoint', 'token_endpoint', 'issuer'];
  for (const field of requiredFields) {
    if (!doc[field]) {
      throw new Error(`Discovery document missing required field: ${field}`);
    }
  }

  // Validate that endpoints use HTTPS
  for (const field of ['authorization_endpoint', 'token_endpoint', 'userinfo_endpoint']) {
    if (doc[field] && !doc[field].startsWith('https://')) {
      throw new Error(`Endpoint ${field} must use HTTPS`);
    }
  }

  discoveryCache.set(authority, doc);
  return doc;
}

