import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import config from '../config';
import { generateRandomString, generateCodeChallenge, generateNonce } from '../utils/crypto';
import { validateIdToken, isTokenExpired, decodeJwtPayload } from '../utils/tokenUtils';
import { fetchDiscoveryDocument } from '../utils/oidcDiscovery';

const AuthContext = createContext(null);

const STORAGE_KEYS = {
  CODE_VERIFIER: 'oidc_code_verifier',
  STATE: 'oidc_state',
  NONCE: 'oidc_nonce',
  ACCESS_TOKEN: 'oidc_access_token',
  ID_TOKEN: 'oidc_id_token',
  REFRESH_TOKEN: 'oidc_refresh_token',
  USER_PROFILE: 'oidc_user_profile',
  RETURN_URL: 'oidc_return_url',
};

function secureSessionStorage(key, value) {
  if (value === undefined) {
    const item = sessionStorage.getItem(key);
    return item ? JSON.parse(item) : null;
  }
  if (value === null) {
    sessionStorage.removeItem(key);
    return;
  }
  sessionStorage.setItem(key, JSON.stringify(value));
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const [discoveryDoc, setDiscoveryDoc] = useState(null);
  const refreshTimerRef = useRef(null);

  // Load discovery document
  useEffect(() => {
    let cancelled = false;
    fetchDiscoveryDocument(config.authority)
      .then((doc) => {
        if (!cancelled) setDiscoveryDoc(doc);
      })
      .catch((err) => {
        if (!cancelled) setError(`Discovery failed: ${err.message}`);
      });
    return () => { cancelled = true; };
  }, []);

  // Restore session on mount
  useEffect(() => {
    const idToken = secureSessionStorage(STORAGE_KEYS.ID_TOKEN);
    const profile = secureSessionStorage(STORAGE_KEYS.USER_PROFILE);

    if (idToken && profile && !isTokenExpired(idToken)) {
      setUser(profile);
      setIsAuthenticated(true);
      scheduleTokenRefresh(idToken);
    } else {
      clearSession();
    }
    setIsLoading(false);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const clearSession = useCallback(() => {
    Object.values(STORAGE_KEYS).forEach((key) => {
      secureSessionStorage(key, null);
    });
    setUser(null);
    setIsAuthenticated(false);
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }
  }, []);

  const scheduleTokenRefresh = useCallback((idToken) => {
    try {
      const payload = decodeJwtPayload(idToken);
      const now = Math.floor(Date.now() / 1000);
      // Refresh 60 seconds before expiry
      const refreshIn = Math.max((payload.exp - now - 60) * 1000, 0);

      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }

      refreshTimerRef.current = setTimeout(() => {
        refreshTokens();
      }, refreshIn);
    } catch {
      // Token can't be decoded, ignore scheduling
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const login = useCallback(async (returnUrl = '/') => {
    if (!discoveryDoc) {
      setError('Discovery document not loaded');
      return;
    }

    try {
      const state = generateRandomString(32);
      const nonce = generateNonce();
      const codeVerifier = generateRandomString(64);
      const codeChallenge = await generateCodeChallenge(codeVerifier);

      // Store PKCE and state parameters securely in session storage
      secureSessionStorage(STORAGE_KEYS.STATE, state);
      secureSessionStorage(STORAGE_KEYS.NONCE, nonce);
      secureSessionStorage(STORAGE_KEYS.CODE_VERIFIER, codeVerifier);
      secureSessionStorage(STORAGE_KEYS.RETURN_URL, returnUrl);

      const params = new URLSearchParams({
        response_type: config.responseType,
        client_id: config.clientId,
        redirect_uri: config.redirectUri,
        scope: config.scope,
        state: state,
        nonce: nonce,
        code_challenge: codeChallenge,
        code_challenge_method: 'S256',
        prompt: 'consent',
      });

      window.location.href = `${discoveryDoc.authorization_endpoint}?${params.toString()}`;
    } catch (err) {
      setError(`Login failed: ${err.message}`);
    }
  }, [discoveryDoc]);

  const handleCallback = useCallback(async (searchParams) => {
    if (!discoveryDoc) {
      throw new Error('Discovery document not loaded');
    }

    setIsLoading(true);
    setError(null);

    try {
      // Check for error response
      const errorParam = searchParams.get('error');
      if (errorParam) {
        const errorDescription = searchParams.get('error_description') || 'Unknown error';
        throw new Error(`Authorization error: ${errorParam} - ${errorDescription}`);
      }

      const code = searchParams.get('code');
      const returnedState = searchParams.get('state');

      if (!code) {
        throw new Error('No authorization code received');
      }

      // Validate state parameter to prevent CSRF
      const storedState = secureSessionStorage(STORAGE_KEYS.STATE);
      if (!storedState || storedState !== returnedState) {
        throw new Error('Invalid state parameter - possible CSRF attack');
      }

      const codeVerifier = secureSessionStorage(STORAGE_KEYS.CODE_VERIFIER);
      const nonce = secureSessionStorage(STORAGE_KEYS.NONCE);

      if (!codeVerifier) {
        throw new Error('No code verifier found');
      }

      // Exchange authorization code for tokens
      const tokenResponse = await fetch(discoveryDoc.token_endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: config.redirectUri,
          client_id: config.clientId,
          code_verifier: codeVerifier,
        }).toString(),
      });

      if (!tokenResponse.ok) {
        const errorBody = await tokenResponse.text();
        throw new Error(`Token exchange failed: ${tokenResponse.status} - ${errorBody}`);
      }

      const tokens = await tokenResponse.json();

      if (!tokens.id_token) {
        throw new Error('No id_token in token response');
      }

      // Validate and decode id_token
      const profile = validateIdToken(
        tokens.id_token,
        config.clientId,
        nonce,
        discoveryDoc.issuer
      );

      // Store tokens securely
      secureSessionStorage(STORAGE_KEYS.ACCESS_TOKEN, tokens.access_token);
      secureSessionStorage(STORAGE_KEYS.ID_TOKEN, tokens.id_token);
      if (tokens.refresh_token) {
        secureSessionStorage(STORAGE_KEYS.REFRESH_TOKEN, tokens.refresh_token);
      }

      const userProfile = {
        sub: profile.sub,
        name: profile.name || '',
        email: profile.email || '',
        picture: profile.picture || '',
        email_verified: profile.email_verified || false,
      };

      secureSessionStorage(STORAGE_KEYS.USER_PROFILE, userProfile);

      // Clean up PKCE parameters
      secureSessionStorage(STORAGE_KEYS.STATE, null);
      secureSessionStorage(STORAGE_KEYS.NONCE, null);
      secureSessionStorage(STORAGE_KEYS.CODE_VERIFIER, null);

      setUser(userProfile);
      setIsAuthenticated(true);
      scheduleTokenRefresh(tokens.id_token);

      // Return the stored return URL
      const returnUrl = secureSessionStorage(STORAGE_KEYS.RETURN_URL) || '/';
      secureSessionStorage(STORAGE_KEYS.RETURN_URL, null);
      return returnUrl;
    } catch (err) {
      clearSession();
      setError(err.message);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, [discoveryDoc, clearSession, scheduleTokenRefresh]);

  const refreshTokens = useCallback(async () => {
    if (!discoveryDoc) return;

    const refreshToken = secureSessionStorage(STORAGE_KEYS.REFRESH_TOKEN);
    if (!refreshToken) {
      clearSession();
      return;
    }

    try {
      const response = await fetch(discoveryDoc.token_endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          refresh_token: refreshToken,
          client_id: config.clientId,
        }).toString(),
      });

      if (!response.ok) {
        throw new Error('Token refresh failed');
      }

      const tokens = await response.json();

      secureSessionStorage(STORAGE_KEYS.ACCESS_TOKEN, tokens.access_token);
      if (tokens.id_token) {
        const profile = validateIdToken(
          tokens.id_token,
          config.clientId,
          null,
          discoveryDoc.issuer
        );

        secureSessionStorage(STORAGE_KEYS.ID_TOKEN, tokens.id_token);

        const userProfile = {
          sub: profile.sub,
          name: profile.name || '',
          email: profile.email || '',
          picture: profile.picture || '',
          email_verified: profile.email_verified || false,
        };

        secureSessionStorage(STORAGE_KEYS.USER_PROFILE, userProfile);
        setUser(userProfile);
        scheduleTokenRefresh(tokens.id_token);
      }

      if (tokens.refresh_token) {
        secureSessionStorage(STORAGE_KEYS.REFRESH_TOKEN, tokens.refresh_token);
      }
    } catch (err) {
      clearSession();
      setError('Session expired. Please log in again.');
    }
  }, [discoveryDoc, clearSession, scheduleTokenRefresh]);

  const logout = useCallback(async () => {
    const idToken = secureSessionStorage(STORAGE_KEYS.ID_TOKEN);
    clearSession();

    if (discoveryDoc?.end_session_endpoint) {
      const params = new URLSearchParams({
        post_logout_redirect_uri: config.postLogoutRedirectUri,
        client_id: config.clientId,
      });

      if (idToken) {
        params.set('id_token_hint', idToken);
      }

      window.location.href = `${discoveryDoc.end_session_endpoint}?${params.toString()}`;
    }
  }, [discoveryDoc, clearSession]);

  const getAccessToken = useCallback(() => {
    const token = secureSessionStorage(STORAGE_KEYS.ACCESS_TOKEN);
    if (token && !isTokenExpired(token)) {
      return token;
    }
    return null;
  }, []);

  const value = {
    user,
    isAuthenticated,
    isLoading,
    error,
    login,
    logout,
    handleCallback,
    getAccessToken,
    refreshTokens,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// src/components/ProtectedRoute.js
import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

function ProtectedRoute({ children }) {
  const { isAuthenticated, isLoading } = useAuth();
  const location = useLocation();

  if (isLoading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <div>
          <div className="spinner" />
          <p>Loading...</p>
        </div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" state={{ from: location.pathname }} replace />;
  }

  return children;
}

export default ProtectedRoute;

